import { Component } from "react";
import dayjs from 'dayjs';

import './style.css';

interface WorkProps {
  name: string,
  beginning: Date,
  end?: Date
}

interface WorkState {
}

class Work extends Component<WorkProps, WorkState>
{
  render()
  {
    let beginningDateString = dayjs(this.props.beginning).format("MM.YYYY");
    let endDateString = this.props.end == null ? "..." : dayjs(this.props.end).format("MM.YYYY");
    let periodString = `${beginningDateString} - ${endDateString}`;

    return (
        <div className="work">

          <div className="work__title">
            <div className="work__title__name">{this.props.name}</div>
            <div className="work__title__period">{periodString}</div>
          </div>

          <div className="work__body">{this.props.children}</div>
        </div>
    ); 
  }
}

export default Work;